// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//==================================================================================================================
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "JA010", compID : "acb_cond_bizTypCd,acb_bizTypCd" },
        { grpCd : "JA060", compID : "acb_eqNrmCd,gr_results:ton" },
        { grpCd : "JA080", compID : "acb_trfAdptCd" },
        { grpCd : "JA090", compID : "acb_degClsCd" }

    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        $c.gus.cfDisableObjects([ed_prdyr, ed_vehclNo, ed_drcrNo, ed_degNm, ed_degForm
                               , acb_eqNrmCd, ed_stdFleffcncy, ed_clntNo_rslts, ed_clntNm_rslts
					           , acb_bizTypCd, acb_trfAdptCd, ed_outBranch, ica_inspDt1, ica_inspDt2
                               , acb_degClsCd, ica_degDt, ica_firstRegDt, ica_chkDt
					           , rd_useYn, ed_rmk]);
    }, {"delay":50});
};

scwin.setCommonCodeCallBack = function(){
    acb_cond_bizTypCd.addItem("전체", "", "", 0);
    acb_cond_bizTypCd.setSelectedIndex(0);

    acb_bizTypCd.addItem("전체", "", "", 0);
    acb_bizTypCd.setSelectedIndex(0);
};


//-------------------------------------------------------------------------
// function name : scwin.f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
	ds_results.removeAll();
	ds_incidentalExpenses.removeAll();

    $c.sbm.execute(sbm_retrieve);    
};

scwin.f_Retrieve_incExpense = function () {
    ds_cond_incidentalExpenses.set("eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"))
    $c.sbm.execute(sbm_retrieve_incExpense);

};

//-------------------------------------------------------------------------
// function name : scwin.f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (){ 
	for(var i = 0 ; i < ds_incidentalExpenses.getRowCount(); i++){
   		if (ds_incidentalExpenses.getRowStatus(i) == "C" 
         || ds_incidentalExpenses.getRowStatus(i) == "D" 
         || ds_incidentalExpenses.getRowStatus(i) == "U" ){
   			if (ds_incidentalExpenses.getCellData(i, "adptYm") == "" 
             && ds_incidentalExpenses.getCellData(i, "adptStDt") == "" ) {
   				await $c.win.alert((i+1)+"번재 행의 적용년월 또는 적용기간은 필수 입력 항목 입니다.");
   				return false;
   			}
   			if (ds_incidentalExpenses.getCellData(i, "adptYm") == "" 
   			    &&  (ds_incidentalExpenses.getCellData(i, "adptStDt") == "" 
                  || ds_incidentalExpenses.getCellData(i, "adptEndDt") == "" ) ) {
   				await $c.win.alert((i+1)+"번재 행의  적용기간의 FROM,TO는  필수 입력 항목 입니다.");
   				return false;
   			}
   			if (ds_incidentalExpenses.getCellData(i, "clntNo") == ""){
   				await $c.win.alert((i+1)+"번째 행의 거래처 정보를 등록해 주십시오.");
   				return false;
   			}
   			if (ds_incidentalExpenses.getCellData(i, "selpchItemCd") == ""){
   				await $c.win.alert((i+1)+"번째 행의 청구/정산 정보를 등록해 주십시오.");
   				return false;
   			}
   			if (ds_incidentalExpenses.getCellData(i, "amtWcrc") == ""){
   				await $c.win.alert((i+1)+"번째 행의 금액을 등록해 주십시오.");
   				return false;
   			}
   			if (ds_incidentalExpenses.getCellData(i, "deductYn")== 1){
   				if (ds_incidentalExpenses.getCellData(i, "adptDeg") == ""){
   					await $c.win.alert((i+1)+"번째 행의 적용차수을 등록해 주십시오.");
   					return false;
   				}
   				if (ds_incidentalExpenses.getCellData(i, "allDeg") == ""){
   					await $c.win.alert((i+1)+"번째 행의 전체차수을 등록해 주십시오.");
   					return false;
   				}
   				if (ds_incidentalExpenses.getCellData(i, "adptTerm") == ""){
   					await $c.win.alert((i+1)+"번째 행의 적용기간을 등록해 주십시오.");
   					return false;
   				}
   			}   			
   		}
   	}
	if (await $c.win.confirm(MSG_CM_CRM_001)){ //저장하시겠습니까?
        $c.sbm.execute(sbm_save);
	}	
}

//-------------------------------------------------------------------------
// function name : f_openPopUp
// function desc : popup
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch, row) {
	switch (disGubun) {
  		case 1:
		    //거래처
		    var condition = "";
		    // if (cnd_chb_repClntYn.checked){
		    if (cbx_repClntYn.getValue() == "T"){
		    	condition = "RP";
		    }
            udc_clnt.setSelectId('retrieveSubsidaryClntList');
            udc_clnt.cfCommonPopUp(scwin.udc_clnt_callBackFunc	    // XML상의 SELECT ID
                                  ,pCode					        // 화면에서의 ??? Code Element의	Value
                                  ,pName					        // 화면에서의 ??? Name Element의	Value
                                  ,pClose					        // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                  ,'5'					            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                  ,null					            // Title순서
                                  ,'150,170'  		                // 보여주는 각 컬럼들의 폭
                                  ,null					            // 컬럼중에서 숨기는	컬럼 지정
                                  ,condition					    // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                  ,null					            // POP-UP뛰을때 원도우의	사용자 정의	폭
                                  ,null					            // POP-UP뛰을때 우도우의	사용자 정의	높이
                                  ,null					            // 윈도우 위치 Y좌표
                                  ,null					            // 윈도우 위치 X좌표
                                  ,null					            // 중복체크여부	("F")
                                  ,pAllSearch				        // 전체검색허용여부	("F")
                                  ,"거래처,거래처코드,거래처명"     // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
			break;

		case 2:
            udc_vehclNo.setSelectId('retrieveSubsidaryVehclList');
			udc_vehclNo.cfCommonPopUp(scwin.udc_vehclNo_callBackFunc	// XML상의 SELECT ID	
									 ,pCode					            // 화면에서의 ??? Code Element의	Value
									 ,pName					            // 화면에서의 ??? Name Element의	Value
									 ,pClose					        // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
									 ,null					            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
									 ,null					            // Title순서	
									 ,null					            // 보여주는 각 컬럼들의 폭	
									 ,null					            // 컬럼중에서 숨기는	컬럼 지정	
									 ,null					            // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
									 ,"400"					            // POP-UP뛰을때 원도우의	사용자 정의	폭
									 ,null					            // POP-UP뛰을때 우도우의	사용자 정의	높이	
									 ,null					            // 윈도우 위치 Y좌표	
									 ,null					            // 윈도우 위치 X좌표
									 ,null					            // 중복체크여부	("F")
									 ,pAllSearch					    // 전체검색허용여부	("F")
									 ,"차량번호,차량단축코드,차량번호"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 
			break;

  		case 3:
		    //거래처
            udc_clnt_rslts.setSelectId('retrieveSubsidaryClntList');
			udc_clnt_rslts.cfCommonPopUp(function(ref){
                                            if (ref != null){
                                                $c.gus.cfSetGridReturnValue(ref, ds_incidentalExpenses, row, "clntNo", "clntNm");	
                                            }
                                        }	    // XML상의 SELECT ID
							            ,pCode					                // 화면에서의 ??? Code Element의	Value
							            ,pName					                // 화면에서의 ??? Name Element의	Value
							            ,'T'					                // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							            ,'5'					                // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							            ,null					                // Title순서
							            ,'150,170'  		                    // 보여주는 각 컬럼들의 폭
							            ,null					                // 컬럼중에서 숨기는	컬럼 지정
							            ,',,,,,'					            // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
							            ,null					                // POP-UP뛰을때 원도우의	사용자 정의	폭
							            ,null					                // POP-UP뛰을때 우도우의	사용자 정의	높이
							            ,null					                // 윈도우 위치 Y좌표
							            ,null					                // 윈도우 위치 X좌표
							            ,null					                // 중복체크여부	("F")
							            ,'F'				                    // 전체검색허용여부	("F")
							            ,"거래처,거래처코드,거래처명"			// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
			break;	

  		case 4:
		    //거래처
			udc_Grdpopup.setSelectId('retrieveSelpchItemInfo');
			udc_Grdpopup.cfCommonPopUp(function(ref){
                                            if (ref != null && ref[0] != "N/A") {
                                                ds_incidentalExpenses.setCellData(row, "selpchItemCd", ref[0]);	//매출항목ID
                                                ds_incidentalExpenses.setCellData(row, "selpchItemNm", ref[1]);	//매출항목명					
                                            }
                                        }	// XML상의 SELECT ID	
									  ,pCode					// 화면에서의 ??? Code Element의	Value
									  ,pName					// 화면에서의 ??? Name Element의	Value
									  ,'T'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
									  ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
		  							  ,null					// Title순서	
		  							  ,null					// 보여주는 각 컬럼들의 폭	
		  							  ,null					// 컬럼중에서 숨기는	컬럼 지정	
		  							  ,',,,,,'					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
		  							  ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
		  							  ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
		  							  ,null					// 윈도우 위치 Y좌표	
		  							  ,null					// 윈도우 위치 X좌표
									  ,null                   // 중복체크여부
									  ,null                   // 전체검색허용여부
									  ,null                   // POP-UP Window Title 검색어1,2(각화면에서 변경할경우)	  							
            ); 
			break;					

		default:
  			break;
  	}
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

scwin.f_AddManager = function (){
	var idx = ds_incidentalExpenses.insertRow();
    ds_incidentalExpenses.setRowPosition(idx);
	var row = ds_incidentalExpenses.getRowPosition();
	ds_incidentalExpenses.setCellData(row, "eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
	ds_incidentalExpenses.setCellData(row, "selpchClsCd", "2");

};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
	$c.gus.cfInitObjects(tbl_cndArea, null);
};

//-------------------------------------------------------------------------
// 행복사 기능
//-------------------------------------------------------------------------
scwin.f_CopyRow = function () {
	var row = ds_incidentalExpenses.getRowPosition();
	if (ds_incidentalExpenses.getRowCount() > 0){
		var idx = ds_incidentalExpenses.insertRow();
        ds_incidentalExpenses.setRowPosition(idx);
		var addAfterRow = ds_incidentalExpenses.getRowPosition();

    	ds_incidentalExpenses.setCellData(addAfterRow, "eqCd", ds_incidentalExpenses.getCellData(row, "eqCd")); 	
		ds_incidentalExpenses.setCellData(addAfterRow, "clntNo", ds_incidentalExpenses.getCellData(row, "clntNo")); 
		ds_incidentalExpenses.setCellData(addAfterRow, "clntNm", ds_incidentalExpenses.getCellData(row, "clntNm"));
		ds_incidentalExpenses.setCellData(addAfterRow, "selpchItemCd", ds_incidentalExpenses.getCellData(row, "selpchItemCd"));
		ds_incidentalExpenses.setCellData(addAfterRow, "selpchItemNm", ds_incidentalExpenses.getCellData(row, "selpchItemNm"));
		ds_incidentalExpenses.setCellData(addAfterRow, "selpchClsCd", ds_incidentalExpenses.getCellData(row, "selpchClsCd"));
		ds_incidentalExpenses.setCellData(addAfterRow, "deductYn", ds_incidentalExpenses.getCellData(row, "deductYn"));
		ds_incidentalExpenses.setCellData(addAfterRow, "amtWcrc", ds_incidentalExpenses.getCellData(row, "amtWcrc"));
		ds_incidentalExpenses.setCellData(addAfterRow, "adptYm", ds_incidentalExpenses.getCellData(row, "adptYm"));
		ds_incidentalExpenses.setCellData(addAfterRow, "adptStDt", ds_incidentalExpenses.getCellData(row, "adptStDt"));
		ds_incidentalExpenses.setCellData(addAfterRow, "adptEndDt", ds_incidentalExpenses.getCellData(row, "adptEndDt"));

		ds_incidentalExpenses.setCellData(addAfterRow, "adptDeg", 0);
		ds_incidentalExpenses.setCellData(addAfterRow, "allDeg", 0);
		ds_incidentalExpenses.setCellData(addAfterRow, "adptTerm", 0);
	}

}; 

