scwin.gr_incidentalExpenses_oncellindexchange = async function (row, columnIndex, oldRow, oldColumnIndex) {
    // if (colid == "clntNo" || colid == "selpchItemCd") {
	// 	gr_incidentalExpenses.UrlImages = "<I>Type='PopupBotton', Url='/common/images/search.gif', Fit='AutoFit', Flat='True'</I>";
	// }else{
	// 	gr_incidentalExpenses.UrlImages = "<I>Type='PopupBotton', Url='/common/images/calendar.gif', Fit='AutoFit', Flat='True'</I>";
	// }

    // //검색이미지
	// if ( colid == "clntNo" || colid == "selpchItemCd") {
	// 	gr_incidentalExpenses.UrlImages = SEARCH_BTN; 
	// }
	// //달력이미지
	// if ( colid == "adptYm" || colid == "adptStDt" || colid == "adptEndDt") {
	// 	gr_incidentalExpenses.UrlImages = CALENDAR_BTN; 
	// }
	//운송비조회
    var colid = gr_incidentalExpenses.getColumnID(columnIndex);
	if (colid == "deductYn"){

		dsResultsRow = ds_results.getRowPosition();

		if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1"){
			ds_cond_trfAmt.set("clntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
        }else{
			ds_cond_trfAmt.set("clntNo", ds_results.getCellData(dsResultsRow, "clntNo"));
		}

		ds_cond_trfAmt.set("bizTypCd", ds_results.getCellData(dsResultsRow, "bizTypCd"));
		ds_cond_trfAmt.set("ton", ds_results.getCellData(dsResultsRow, "ton"));		
		ds_cond_trfAmt.set("chkClntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
		ds_cond_trfAmt.set("eqCd", ds_results.getCellData(dsResultsRow, "eqCd"));
		ds_cond_trfAmt.set("selpchClsCd", ds_incidentalExpenses.getCellData(row, "selpchClsCd"));

        var rs = await $c.sbm.execute(sbm_retrieve_trfAmt);	
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){
            if (ds_incidentalExpenses.getCellData(row, "selpchItemCd") == "1039"){ //운송임
                if (ds_trfAmt.get("adptDt") == ""){
                    await $c.win.alert("조회된 계약요율이 없습니다.");
                    return false;
                }else{
                    if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1"){ //매출
                        ds_incidentalExpenses.setCellData(row, "amtWcrc", ds_trfAmt.get("sellAmt"));
                    }else if (ds_incidentalExpenses.getCellData(row,"selpchClsCd") == "2"){ //매입
                        if (ds_results.getCellData(dsResultsRow, "trfAdptCd") == "01" 
                         || ds_results.getCellData(dsResultsRow, "trfAdptCd") == "03"){ //장축
                            ds_incidentalExpenses.setCellData(row, "amtWcrc", ds_trfAmt.get("pchsLongAmt"));
                        }else if (ds_results.getCellData(dsResultsRow,"trfAdptCd") == "02"){
                            ds_incidentalExpenses.setCellData(row, "amtWcrc", ds_trfAmt.get("pchsSuperLongAmt"));
                        }
                    }
                    ds_incidentalExpenses.setCellData(row, "deductYn", "0"); //공제여부 - no
                }
            }    
        };
	}
};

scwin.gr_incidentalExpenses_ontextimageclick = function (row, columnIndex) {
	var colid = gr_incidentalExpenses.getColumnID(columnIndex);
	switch (colid) {

		case "selpchItemCd":

			pCode = ds_incidentalExpenses.getCellData(row, "selpchItemCd");		// 매출항목ID
			pName = "";

			udc_Grdpopup.setSelectId('retrieveSelpchItemInfo'); // XML상의 SELECT ID	
			udc_Grdpopup.cfCommonPopUp(function(ref){
                                        if (ref != null && ref[0] != "N/A") {
                                            ds_incidentalExpenses.setCellData(row, "selpchItemCd", ref[0]);	//매출항목ID
                                            ds_incidentalExpenses.setCellData(row, "selpchItemNm", ref[1]);	//매출항목명					
                                        }
                                    }	
									,pCode					// 화면에서의 ??? Code Element의	Value
									,pName					// 화면에서의 ??? Name Element의	Value
									,'T'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
									,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
		  							,null					// Title순서	
		  							,null					// 보여주는 각 컬럼들의 폭	
		  							,null					// 컬럼중에서 숨기는	컬럼 지정	
		  							,',,,,,'					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
		  							,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
		  							,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
		  							,null					// 윈도우 위치 Y좌표	
		  							,null					// 윈도우 위치 X좌표
									,null                   // 중복체크여부
									,null                   // 전체검색허용여부
									,null                   // POP-UP Window Title 검색어1,2(각화면에서 변경할경우)	  							
            ); 
			break;

		case "clntNo":
			pCode = ds_incidentalExpenses.getCellData(row, "clntNo");
			pName = "";

            udc_Grdpopup.setSelectId('retrieveSubsidaryClntList'); // XML상의 SELECT ID	
			udc_Grdpopup.cfCommonPopUp(function(ref){
                                        if (ref != null){
                                            $c.gus.cfSetGridReturnValue(ref, ds_incidentalExpenses, row, "clntNo", "clntNm");	
                                        }
                                    }
							        ,pCode					// 화면에서의 ??? Code Element의	Value
							        ,pName					// 화면에서의 ??? Name Element의	Value
							        ,'T'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							        ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							        ,null					// Title순서
							        ,'150,170'  		    // 보여주는 각 컬럼들의 폭
							        ,null					// 컬럼중에서 숨기는	컬럼 지정
							        ,',,,,,'					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
							        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
							        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이
							        ,null					// 윈도우 위치 Y좌표
							        ,null					// 윈도우 위치 X좌표
							        ,null					// 중복체크여부	("F")
							        ,'F'				// 전체검색허용여부	("F")
							        ,"거래처,거래처코드,거래처명"				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
			break;

		case "clntNm":
			pCode = "";
			pName = ds_incidentalExpenses.getCellData(row, "clntNm");
			udc_Grdpopup.setSelectId('retrieveSubsidaryClntList'); // XML상의 SELECT ID	
			udc_Grdpopup.cfCommonPopUp(function(ref){
                                        if (ref != null){
                                            $c.gus.cfSetGridReturnValue(ref, ds_incidentalExpenses, row, "clntNo", "clntNm");	
                                        }
                                    }
							        ,pCode					// 화면에서의 ??? Code Element의	Value
							        ,pName					// 화면에서의 ??? Name Element의	Value
							        ,'T'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							        ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							        ,null					// Title순서
							        ,'150,170'  		    // 보여주는 각 컬럼들의 폭
							        ,null					// 컬럼중에서 숨기는	컬럼 지정
							        ,',,,,,'					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
							        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
							        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이
							        ,null					// 윈도우 위치 Y좌표
							        ,null					// 윈도우 위치 X좌표
							        ,null					// 중복체크여부	("F")
							        ,'F'				// 전체검색허용여부	("F")
							        ,"거래처,거래처코드,거래처명"				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
			break;	
		// case "adptYm":
		// 	cfOpenCalendar(gr_incidentalExpenses, row, colid);
		// 	break;

		// case "adptStDt":
		// 	cfOpenCalendar(gr_incidentalExpenses, row, colid);
		// 	break;

		// case "adptEndDt":
		// 	cfOpenCalendar(gr_incidentalExpenses, row, colid);
		// 	break;
	}
};

scwin.gr_incidentalExpenses_onafteredit = async function (row, columnIndex, value) {
    var colid = gr_incidentalExpenses.getColumnID(columnIndex);
    if (colid == "clntNo"){
		var clntNo = ds_incidentalExpenses.getCellData(row, "clntNo");
		if (clntNo == ""){
			ds_incidentalExpenses.setCellData(row, "clntNo", "");
			return;
		}
		scwin.f_openCommonPopUp(3, clntNo, "", "F", "F", row);	
	}

	if (colid == "selpchItemCd"){
		var selpchItemCd = ds_incidentalExpenses.getCellData(row, "selpchItemCd");
		if (selpchItemCd == ""){
			ds_incidentalExpenses.setCellData(row, "selpchItemCd", "");
			return;
		}
		scwin.f_openCommonPopUp(4, selpchItemCd, "", "F", "F", row);	
	}

    // gr_incidentalExpenses event=OnCloseUp(row,colid)
    if (colid == "selpchClsCd" ){

		var dsResultsRow = ds_results.getRowPosition();

		if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1"){
			ds_cond_trfAmt.set("clntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
		} else {
			ds_cond_trfAmt.set("clntNo", ds_results.getCellData(dsResultsRow, "clntNo"));
		}

		ds_cond_trfAmt.set("bizTypCd", ds_results.getCellData(dsResultsRow, "bizTypCd"));
		ds_cond_trfAmt.set("ton", ds_results.getCellData(dsResultsRow, "ton"));

		ds_cond_trfAmt.set("chkClntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
		ds_cond_trfAmt.set("eqCd", ds_results.getCellData(dsResultsRow, "eqCd"));
		ds_cond_trfAmt.set("selpchClsCd", ds_incidentalExpenses.getCellData(row, "selpchClsCd"));

        var rs = await $c.sbm.execute(sbm_retrieve_trfAmt);	
        if (rs.responseJSON.resultDataSet[0].Msg == "SUCC"){

            if (ds_trfAmt.get("chkClntNoExistYn") == "NO" && ds_incidentalExpenses.getCellData(row, "clntNo") != "999910"){
                var selpchClsNm = "";
                if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1"){
                    selpchClsNm = "청구";
                }else if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "2"){
                    selpchClsNm = "정산";
                }
                await $c.win.alert("거래처 " + ds_incidentalExpenses.getCellData(row, "clntNm")
                                 + "는(은) " + ds_results.getCellData(dsResultsRow, "vehclNo")
                                 + " 차량의 " + selpchClsNm + "거래처로 등록되지 않았습니다. "
                                 + "차량관리의 거래처별소속차량관리 화면에서 " + selpchClsNm
                                 + "거래처로 등록해 주시기 바랍니다." 
                                 + "공통거래처(999910)은 제약없이 입력 가능합니다." 
                );
                return false;
            }

            if (ds_incidentalExpenses.getCellData(row, "selpchItemCd") == "1039"){ //운송임
                if (ds_trfAmt.get("adptDt") == ""){
                    await $c.win.alert("조회된 계약요율이 없습니다.");
                    return false;
                }else{
                    if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1"){ //매출
                        ds_incidentalExpenses.setCellData(row, "amtWcrc", ds_trfAmt.get("sellAmt"));
                    } else if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "2"){ //매입
                        if (ds_results.getCellData(dsResultsRow, "trfAdptCd") == "01" 
                         || ds_results.getCellData(dsResultsRow, "trfAdptCd") == "03"){ //장축
                            ds_incidentalExpenses.setCellData(row, "amtWcrc", ds_trfAmt.get("pchsLongAmt"));
                        }else if (ds_results.getCellData(dsResultsRow,"trfAdptCd") == "02"){
                            ds_incidentalExpenses.setCellData(row, "amtWcrc", ds_trfAmt.get("pchsSuperLongAmt"));
                        }
                    }
                    ds_incidentalExpenses.setCellData(row, "deductYn", "0"); //공제여부 - no
                }
            }
        }
	}	
};

